const { app } = require('@azure/functions');

// ===========================================================================
// DEV-ONLY CREDENTIALS — MUST be moved to Azure Key Vault before production!
// In production, these would be referenced as:
//   @Microsoft.KeyVault(SecretUri=https://<vault-name>.vault.azure.net/secrets/<secret-name>/)
// stored in Application Settings, NOT in code.
// ===========================================================================
const DEV_CONFIG = {
    SENDGRID_API_KEY: 'SG.azure_demo_key_123',
    TWILIO_ACCOUNT_SID: 'AC1234567890abcdef',
    TWILIO_AUTH_TOKEN: process.env.TWILIO_AUTH_TOKEN || 'dev_twilio_auth_token_placeholder',
    TWILIO_PHONE_NUMBER: process.env.TWILIO_PHONE_NUMBER || '+15551234567',
    SENDGRID_FROM_EMAIL: process.env.SENDGRID_FROM_EMAIL || 'noreply@example.com',
};

// Helper to get config value: prefer environment variables (Key Vault refs in prod),
// fall back to dev hardcoded values
function getConfig(key) {
    return process.env[key] || DEV_CONFIG[key];
}

// ---------- SendGrid Email Service ----------
class EmailService {
    constructor() {
        this.apiKey = getConfig('SENDGRID_API_KEY');
        this.fromEmail = getConfig('SENDGRID_FROM_EMAIL');
        this.sendgridApiUrl = 'https://api.sendgrid.com/v3/mail/send';
    }

    async sendEmail({ to, subject, textContent, htmlContent }) {
        if (!to || !subject) {
            throw new Error('Missing required email fields: "to" and "subject" are required.');
        }

        const payload = {
            personalizations: [
                {
                    to: Array.isArray(to) ? to.map(email => ({ email })) : [{ email: to }],
                    subject: subject,
                },
            ],
            from: { email: this.fromEmail },
            content: [],
        };

        if (textContent) {
            payload.content.push({ type: 'text/plain', value: textContent });
        }
        if (htmlContent) {
            payload.content.push({ type: 'text/html', value: htmlContent });
        }
        if (payload.content.length === 0) {
            payload.content.push({ type: 'text/plain', value: '' });
        }

        const response = await fetch(this.sendgridApiUrl, {
            method: 'POST',
            headers: {
                'Authorization': `Bearer ${this.apiKey}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(payload),
        });

        if (!response.ok) {
            const errorBody = await response.text();
            throw new Error(`SendGrid API error (${response.status}): ${errorBody}`);
        }

        return {
            success: true,
            statusCode: response.status,
            message: `Email sent successfully to ${Array.isArray(to) ? to.join(', ') : to}`,
        };
    }
}

// ---------- Twilio SMS Service ----------
class SmsService {
    constructor() {
        this.accountSid = getConfig('TWILIO_ACCOUNT_SID');
        this.authToken = getConfig('TWILIO_AUTH_TOKEN');
        this.fromNumber = getConfig('TWILIO_PHONE_NUMBER');
        this.twilioApiUrl = `https://api.twilio.com/2010-04-01/Accounts/${this.accountSid}/Messages.json`;
    }

    async sendSms({ to, body }) {
        if (!to || !body) {
            throw new Error('Missing required SMS fields: "to" and "body" are required.');
        }

        const params = new URLSearchParams();
        params.append('To', to);
        params.append('From', this.fromNumber);
        params.append('Body', body);

        const authHeader = 'Basic ' + Buffer.from(`${this.accountSid}:${this.authToken}`).toString('base64');

        const response = await fetch(this.twilioApiUrl, {
            method: 'POST',
            headers: {
                'Authorization': authHeader,
                'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: params.toString(),
        });

        const responseData = await response.json();

        if (!response.ok) {
            throw new Error(
                `Twilio API error (${response.status}): ${responseData.message || JSON.stringify(responseData)}`
            );
        }

        return {
            success: true,
            statusCode: response.status,
            messageSid: responseData.sid,
            message: `SMS sent successfully to ${to}`,
        };
    }
}

// ---------- Azure Function: Send Email ----------
app.http('sendEmail', {
    methods: ['POST'],
    authLevel: 'function',
    route: 'notifications/email',
    handler: async (request, context) => {
        context.log('Processing email send request');

        try {
            const body = await request.json();
            const { to, subject, textContent, htmlContent } = body;

            if (!to || !subject) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'Missing required fields. "to" and "subject" are required.',
                    },
                };
            }

            const emailService = new EmailService();
            const result = await emailService.sendEmail({ to, subject, textContent, htmlContent });

            context.log(`Email sent successfully to ${to}`);
            return {
                status: 200,
                jsonBody: result,
            };
        } catch (error) {
            context.error(`Email send failed: ${error.message}`);
            return {
                status: 500,
                jsonBody: {
                    success: false,
                    error: error.message,
                },
            };
        }
    },
});

