// ---------- Azure Function: Send Both Email & SMS ----------
app.http('sendNotification', {
    methods: ['POST'],
    authLevel: 'function',
    route: 'notifications/send',
    handler: async (request, context) => {
        context.log('Processing combined notification request');

        try {
            const body = await request.json();
            const { email, sms } = body;

            if (!email && !sms) {
                return {
                    status: 400,
                    jsonBody: {
                        success: false,
                        error: 'At least one of "email" or "sms" must be provided.',
                        example: {
                            email: {
                                to: 'recipient@example.com',
                                subject: 'Hello',
                                textContent: 'Hello from Azure!',
                                htmlContent: '<h1>Hello from Azure!</h1>',
                            },
                            sms: {
                                to: '+1234567890',
                                message: 'Hello from Azure!',
                            },
                        },
                    },
                };
            }

            const results = {
                success: true,
                email: null,
                sms: null,
                errors: [],
            };

            // Send email if requested
            if (email) {
                try {
                    const emailService = new EmailService();
                    results.email = await emailService.sendEmail({
                        to: email.to,
                        subject: email.subject,
                        textContent: email.textContent,
                        htmlContent: email.htmlContent,
                    });
                } catch (emailError) {
                    results.errors.push({ channel: 'email', error: emailError.message });
                    results.email = { success: false, error: emailError.message };
                }
            }

            // Send SMS if requested
            if (sms) {
                try {
                    const smsService = new SmsService();
                    results.sms = await smsService.sendSms({
                        to: sms.to,
                        body: sms.message,
                    });
                } catch (smsError) {
                    results.errors.push({ channel: 'sms', error: smsError.message });
                    results.sms = { success: false, error: smsError.message };
                }
            }

            // Determine overall success
            results.success = results.errors.length === 0;
            const statusCode = results.success ? 200 : results.errors.length === (email && sms ? 2 : 1) ? 500 : 207;

            context.log(`Notification processing complete. Errors: ${results.errors.length}`);
            return {
                status: statusCode,
                jsonBody: results,
            };
        } catch (error) {
            context.error(`Notification processing failed: ${error.message}`);
            return {
                status: 500,
                jsonBody: {
                    success: false,
                    error: error.message,
                },
            };
        }
    },
});

// ---------- Azure Function: Health Check ----------
app.http('healthCheck', {
    methods: ['GET'],
    authLevel: 'anonymous',
    route: 'notifications/health',
    handler: async (request, context) => {
        const isProduction = process.env.NODE_ENV === 'production' ||
                             process.env.AZURE_FUNCTIONS_ENVIRONMENT === 'Production';

        // Check if we're using env vars (Key Vault) or hardcoded dev values
        const usingKeyVault = {
            SENDGRID_API_KEY: !!process.env.SENDGRID_API_KEY,
            TWILIO_ACCOUNT_SID: !!process.env.TWILIO_ACCOUNT_SID,
            TWILIO_AUTH_TOKEN: !!process.env.TWILIO_AUTH_TOKEN,
        };

        const allSecretsInKeyVault = Object.values(usingKeyVault).every(v => v);

        return {
            status: 200,
            jsonBody: {
                status: 'healthy',
                timestamp: new Date().toISOString(),
                environment: isProduction ? 'production' : 'development',
                secretsManagement: {
                    usingKeyVault: usingKeyVault,
                    allSecretsSecured: allSecretsInKeyVault,
                    warning: !allSecretsInKeyVault
                        ? 'Some secrets are using hardcoded dev values. Migrate to Azure Key Vault before production deployment.'
                        : undefined,
                },
                endpoints: {
                    sendEmail: 'POST /api/notifications/email',
                    sendSms: 'POST /api/notifications/sms',
                    sendBoth: 'POST /api/notifications/send',
                    health: 'GET /api/notifications/health',
                },
            },
        };
    },
});